CREATE TABLE public.deposit_requests (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), profile_id UUID REFERENCES public.profiles(id) ON DELETE CASCADE, transaction_id UUID REFERENCES public.transactions(id) ON DELETE SET NULL, amount DECIMAL(18, 2) NOT NULL, currency TEXT DEFAULT 'NGN', status TEXT DEFAULT 'pending', payment_proof_url TEXT, payment_reference TEXT, payment_date TIMESTAMPTZ, bank_name TEXT, sender_account_name TEXT, sender_account_number TEXT, admin_notes TEXT, verified_by UUID, verified_at TIMESTAMPTZ, created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW())